SELECT COUNT(subcategory_id) AS active_subcategories_count
FROM rate_subcategories
WHERE is_active = 1;

SELECT COUNT(*) AS non_public_files_count
FROM rate_files
WHERE is_public = 0;

SELECT COUNT(*) AS total_reliable_primary_sources
FROM rate_sources
WHERE is_reliable = 1 AND is_primary = 1;

SELECT source_name, COUNT(*) AS source_count
FROM rate_sources
GROUP BY source_name;

SELECT county_name, population, poverty_rate, AVG(poverty_rate) OVER () as average_poverty_rate
   FROM counties
   WHERE county_type = 'rural' AND population > 50000;

SELECT MAX(rate_value) AS max_rate_value
FROM county_rates
WHERE county_id = 1 AND year = 2020;
